import SwiftUI
import CoreText

@main
struct MemolaneApp: App {
    enum AppScreen {
        case intro, unveil, main
    }
    
    @State private var currentScreen: AppScreen = .intro
    
    init() {
        Self.registerKomorebiFontFromBase64()
    }
    
    static func registerKomorebiFontFromBase64() {
        let base64String = ""
        
        guard let data = Data(base64Encoded: base64String),
              let provider = CGDataProvider(data: data as CFData),
              let cgFont = CGFont(provider) else {
            print("❌ Failed to create CGFont from embedded base64 data")
            return
        }
        
        var error: Unmanaged<CFError>?
        if CTFontManagerRegisterGraphicsFont(cgFont, &error) {
            print("✅ Komorebi font registered successfully! (Embedded)")
        } else {
            let desc = error?.takeRetainedValue().localizedDescription ?? ""
            if desc.contains("already registered") {
                print("✅ Komorebi font was already registered")
            } else {
                print("❌ Font registration issue: \(desc)")
            }
        }
    }
    
    var body: some Scene {
        WindowGroup {
            ZStack {
                switch currentScreen {
                case .intro:
                    LumeIntroView()
                        .onTapGesture {
                            withAnimation(.easeInOut(duration: 1.0)) {
                                currentScreen = .unveil
                            }
                        }
                        .transition(.opacity)
                case .unveil:
                    UnveilStoryView {
                        withAnimation(.easeInOut(duration: 1.0)) {
                            currentScreen = .main
                        }
                    }
                    .transition(.opacity)
                case .main:
                    ContentView()
                        .transition(.opacity)
                }
            }
        }
    }
}

